record.field:
{
  "type": "object",
  "title": "GetMeResponse",
  "properties": {
    "user": {
      "type": "object",
      "properties": {
        "id":                 {"type": "integer", "example": 2},
        "name":               {"type": "string",  "example": "John Doe"},
        "email":              {"type": "string",  "format": "email", "example": "john@example.com"},
        "login":              {"type": "string",  "example": "john"},
        "phone":              {"type": "string",  "example": "1133334444"},
        "mobile":             {"type": "string",  "example": "11999998888"},
        "role":               {"type": "string",  "nullable": true, "example": "manager"},
        "companies": {
          "type": "array",
          "items": {
            "type": "object",
            "properties": {
              "id":      {"type": "integer", "example": 1},
              "name":    {"type": "string",  "example": "Real Estate Company"},
              "cnpj":    {"type": "string",  "example": "12.345.678/0001-99"},
              "email":   {"type": "string",  "example": "company@example.com"},
              "phone":   {"type": "string",  "example": "1133334444"},
              "website": {"type": "string",  "example": "https://example.com"}
            }
          }
        },
        "default_company_id": {"type": "integer", "nullable": true, "example": 1},
        "is_admin":           {"type": "boolean", "example": false},
        "active":             {"type": "boolean", "example": true}
      }
    }
  }
}
